input.old_string:
f.addEventListener('submit', (e) => {
  e.preventDefault();
  const headline = document.getElementById('headline').value.trim();
  const byline = document.getElementById('byline').value.trim();
  if (!headline || !byline) return;
  const item = {
    kicker: document.getElementById('kicker').value.trim(),
    headline,
    summary: document.getElementById('summary').value.trim(),
    byline: byline.toLowerCase().startsWith('by ') ? byline : 'By ' + byline,
    ts: Date.now()
  };
  saveTip(item);
  showThanks();
});

input.new_string:
f.addEventListener('submit', (e) => {
  e.preventDefault();
  const headline = document.getElementById('headline').value.trim();
  let byline = document.getElementById('byline').value.trim();
  if (!headline) return;
  if (!byline) {
    byline = 'By Anonymous';
  } else if (!byline.toLowerCase().startsWith('by ')) {
    byline = 'By ' + byline;
  }
  const item = {
    kicker: document.getElementById('kicker').value.trim(),
    headline,
    summary: document.getElementById('summary').value.trim(),
    byline,
    ts: Date.now()
  };
  saveTip(item);
  showThanks();
});

